# New algorithm description: {Select the next customer by balancing the urgency of imminent deadlines with minimizing total travel distance and penalizing conflicts with other trucks.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(position1, position2):
        return np.linalg.norm(position1 - position2) / truck_speed

    def score_customer(candidate_index):
        candidate_pos = unvisited_customers[candidate_index]
        travel_time = calculate_travel_time(cur_truck_pos, candidate_pos)
        arrival_time = current_time + travel_time
        start_time, end_time = time_windows[candidate_index]

        conflict_penalty = sum(calculate_travel_time(pos, candidate_pos) < travel_time for pos in all_truck_pos)

        if arrival_time <= start_time:
            waiting_time = start_time - arrival_time
            time_penalty = 0
        elif arrival_time > start_time and arrival_time <= end_time:
            waiting_time = 0
            time_penalty = 0
        else:
            waiting_time = 0
            time_penalty = np.inf

        urgency_priority = 1 / (end_time - current_time + 1)
        adjusted_potential_gain = max(0, np.linalg.norm(depot_pos - cur_truck_pos) - travel_time)

        return -(travel_time + time_penalty + waiting_time - adjusted_potential_gain * urgency_priority + conflict_penalty)

    best_score = -np.inf
    best_node = None
    for index in range(len(unvisited_customers)):
        score = score_customer(index)
        if score > best_score:
            best_score = score
            best_node = index

    return best_node

